import 'package:flutter_test/flutter_test.dart';import 'package:easyremote/src/models/sync_conflict.dart';import 'package:easyremote/src/services/sync_conflict_detector.dart';void main(){test('detects conflict types',(){final result=SyncConflictDetector().compare(localHashes:{'a':'1','b':'2'},remoteHashes:{'b':'3','c':'4'});expect(result.any((c)=>c.path=='a'&&c.type==SyncConflictType.localOnly),isTrue);expect(result.any((c)=>c.path=='b'&&c.type==SyncConflictType.bothChanged),isTrue);expect(result.any((c)=>c.path=='c'&&c.type==SyncConflictType.remoteOnly),isTrue);});}
